  headers: { Authorization: `Bearer ${process.env.SCRAPIO_API_KEY}` },
});
const data = await resp.json();
console.log(data.organic_results);

const resp = await fetch("https://api.scrapio.dev/v1/crawl", {
  method: "POST",
  headers: { Authorization: `Bearer ${process.env.SCRAPIO_API_KEY}`, "Content-Type": "application/json" },
  body: JSON.stringify({ seeds: ["https://example.com"], max_pages: 5, output: ["markdown"] }),
});
const { result } = await resp.json();
result.pages.forEach(p => console.log(p.url, p.status));

const resp = await fetch("https://api.scrapio.dev/v1/map", {
  method: "POST",
  headers: { Authorization: `Bearer ${process.env.SCRAPIO_API_KEY}`, "Content-Type": "application/json" },
  body: JSON.stringify({ seeds: ["https://example.com"], max_urls: 20 }),
});
const { result } = await resp.json();
result.urls.forEach(u => console.log(u.url));

const resp = await fetch("https://api.scrapio.dev/v1/interact", {
  method: "POST",
  headers: { Authorization: `Bearer ${process.env.SCRAPIO_API_KEY}`, "Content-Type": "application/json" },
  body: JSON.stringify({
    url: "https://example.com",
    actions: [{ type: "click", selector: "a" }],
    output: ["markdown"],
  }),
});
const { result } = await resp.json();
console.log(result.outputs.markdown);

const resp = await fetch("https://api.scrapio.dev/v1/search", {
  method: "POST",
  headers: { Authorization: `Bearer ${process.env.SCRAPIO_API_KEY}`, "Content-Type": "application/json" },
  body: JSON.stringify({ query: "best TypeScript frameworks", max_results: 5, fetch_results: true, output: ["markdown"] }),
});
const { result } = await resp.json();
result.results.forEach(r => console.log(r.title, r.url));

import os, time, requests
headers = {"Authorization": f"Bearer {os.environ['SCRAPIO_API_KEY']}"}
while True:
    r = requests.get("https://api.scrapio.dev/v1/jobs/job_abc123", headers=headers).json()
    if r["result_available"] or r["status"] in ("failed", "cancelled"):
        break
    time.sleep(3)

const headers = { Authorization: `Bearer ${process.env.SCRAPIO_API_KEY}` };
let status;
do {
  await new Promise(r => setTimeout(r, 3000));
  status = await fetch("https://api.scrapio.dev/v1/jobs/job_abc123", { headers }).then(r => r.json());
} while (!status.result_available && !["failed","cancelled"].includes(status.status));

const resp = await fetch("https://api.scrapio.dev/v1/jobs", {
  method: "POST",
  headers: { Authorization: `Bearer ${process.env.SCRAPIO_API_KEY}`, "Content-Type": "application/json", "Idempotency-Key": "my-job-001" },
  body: JSON.stringify({ kind: "fetch", input: { url: "https://example.com", output: ["markdown"] } }),
});
const { job_id } = await resp.json();

const result = await fetch("https://api.scrapio.dev/v1/jobs/job_abc123/result", {
  headers: { Authorization: `Bearer ${process.env.SCRAPIO_API_KEY}` },
}).then(r => r.json());
console.log(result.outputs.markdown);

const resp = await fetch("https://api.scrapio.dev/v1/jobs/job_abc123/cancel", {
